sql:
SELECT bike_id, COUNT(record_id) AS total_maintenance_records
FROM maintenance_records
GROUP BY bike_id;

SELECT cycle_id, average_speed, distance_traveled
FROM cycles
ORDER BY cycle_id;

SELECT cycle_id, pickup_speed, battery_life
FROM cycles
WHERE pickup_speed > 15 AND battery_life < 30;

external_knowledge:
- In the metaphorical context, 'traditional fleets' represent traditional operations (traditional_scenario = 1), while 'autonomous fleets' represent operations with autonomous bikes (num_autonomous_bikes > 0).;
- The 'voyage distance' in the metaphor is a representation of the 'distance_traveled' in the SQL query, and the 'endurance of their vessels' refers to the 'battery_life'.;
- The term 'navigation course through the seas of performance' emphasizes the comparative analysis of performance metrics—distance and battery life—between traditional and autonomous scenarios.;

sql:
SELECT user_name
FROM user_accounts
WHERE user_rating = (SELECT MAX(user_rating) FROM user_accounts);

SELECT AVG(battery_life) AS average_battery_life
FROM cycles
WHERE battery_gain_percent > 50;

SELECT ch.bike_id, ch.session_id, ch.session_status, st.station_id, st.maintenance_status
FROM charging_sessions ch
JOIN stations st ON ch.station_id = st.station_id;

SELECT AVG(battery_life) AS average_battery_life
FROM cycles
WHERE num_users > 30;

SELECT AVG(battery_percent)
FROM battery_logs
WHERE cycle_id IN (
    SELECT cycle_id
    FROM cycles
    WHERE num_autonomous_bikes = (
        SELECT MAX(num_autonomous_bikes) 
        FROM cycles
    )
);

SELECT cycle_id
FROM cycles
WHERE battery_life < (SELECT AVG(battery_life) FROM cycles);
